import json, subprocess, time, sys
p=subprocess.Popen(['codex','app-server','proxy'], stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, bufsize=1)
msgs=[
 {'method':'initialize','id':1,'params':{'clientInfo':{'name':'automation_probe','title':'Automation Probe','version':'0.1.0'},'capabilities':{'experimentalApi':True}}},
 {'method':'initialized','params':{}},
 {'method':'thread/list','id':2,'params':{'limit':1,'includeArchived':False,'skipRepair':True}},
]
for m in msgs:
    p.stdin.write(json.dumps(m,separators=(',',':'))+'\n')
    p.stdin.flush()
end=time.time()+10
while time.time()<end:
    line=p.stdout.readline()
    if line:
        print(line.rstrip())
        if '"id":2' in line:
            break
    elif p.poll() is not None:
        break
p.terminate()
try:
    p.wait(timeout=2)
except subprocess.TimeoutExpired:
    p.kill()
err=p.stderr.read()
if err:
    print('STDERR:',err,file=sys.stderr)
PY

