import tomllib
from datetime import datetime, timedelta
from pathlib import Path
WEEKDAYS={'MO':0,'TU':1,'WE':2,'TH':3,'FR':4,'SA':5,'SU':6}
def parse(rrule):
    if rrule.startswith('RRULE:'): rrule=rrule[6:]
    parts={}
    for p in rrule.split(';'):
        if '=' in p:
            k,v=p.split('=',1); parts[k]=v.split(',')
    return parts
now=datetime.now().astimezone()
for path in sorted(Path('/home/adam-blumoff/.codex/automations').glob('*/automation.toml')):
    cfg=tomllib.loads(path.read_text())
    parts=parse(cfg['rrule'])
    hours=[int(x) for x in parts.get('BYHOUR',['0'])]
    minutes=[int(x) for x in parts.get('BYMINUTE',['0'])]
    days=parts.get('BYDAY')
    candidate=now.replace(second=0,microsecond=0)
    for _ in range(14*24*60):
        if candidate.hour in hours and candidate.minute in minutes:
            if not days or candidate.weekday() in {WEEKDAYS[d] for d in days if d in WEEKDAYS}:
                if candidate > now:
                    print(cfg['id'], cfg.get('execution_environment'), candidate.isoformat())
                    break
        candidate += timedelta(minutes=1)
PY
